import React, { useEffect } from "react";
import UserLayout from "@/layout/UserLayout";
import DashboardLayout from "@/layout/DashboardLayout";
import { getMyConnectionRequest } from "@/config/redux/action/authAction";
import { useDispatch, useSelector } from "react-redux";
export default function MyConnections(){


  const dispatch = useDispatch();

  const authState = useSelector((state)=> state.auth)

  useEffect(()=>{
     console.log(localStorage.getItem("token"));
    dispatch(getMyConnectionRequest({token: localStorage.getItem("token")}));
  },[])

  useEffect(()=>{
     

    if(authState.connectionRequests.length !=0){
      console.log(authState.connectionRequests)
    }
  },[authState.connectionRequests])
    return(
         <UserLayout>
      <DashboardLayout>
        <div>
          <h1>My Connections</h1>

          {authState.connectionRequests.length!=0 && authState.connectionRequests.map((user, index)=>{
            return(
              <div className={styles.userCard} key={index}></div>
            )
          })}
        </div>
      </DashboardLayout>
    </UserLayout>
    )
}